1	/**
2	 * `revealTodos` stage. Active once `onboarding_todos` is non-empty and the
3	 * user hasn't acked yet.
4	 *
5	 * Two sub-states:
6	 * - **Grid mode** (default): show the suggested todos. User can click "Run"
7	 *   on one (→ `executeTodo`, flips into stream mode) or "I'll do it later"
8	 *   (→ `ackTodos`, advances to workflows).
9	 * - **Stream mode** (`state.todoExecutionStarted`): the todo grid is replaced
10	 *   in-place by the live chat stream so the agent's processing is visible
11	 *   without leaving the onboarding shell. Once the agent finishes
12	 *   (`chat.isTodoExecutionDone`) a Continue button dispatches `ackTodoDemo`
13	 *   to advance to the workflows stage.
14	 */
15	
16	"use client";
17	
18	import { Button } from "@heroui/button";
19	import { Chip } from "@heroui/chip";
20	import { CheckmarkCircle02Icon, Mail01Icon } from "@icons";
21	import * as m from "motion/react-m";
22	import type { Dispatch } from "react";
23	import { useCallback } from "react";
24	import { REVEAL_TODOS_INTRO } from "../../constants/messages";
25	import { MOTION_COMPOSER_CTA } from "../../constants/motion";
26	import type { UseOnboardingChatReturn } from "../../hooks/useOnboardingChat";
27	import type { Action, OnboardingState } from "../../state/types";
28	import { OnboardingCTAButton } from "../OnboardingCTAButton";
29	import { OnboardingTodoCards } from "../OnboardingTodoCards";
30	import { RevealIntroBubble } from "../RevealIntroBubble";
31	import { OnboardingChatStream } from "./Chat";
32	
33	interface RevealTodosProps {
34	  state: OnboardingState;
35	  dispatch: Dispatch<Action>;
36	  /** Run-now demo chat — separate throwaway conversation, NOT the welcome
37	   *  conversation. See `useChatStage`. */
38	  chat: UseOnboardingChatReturn;
39	}
40	
41	function generateConvoId(): string {
42	  if (typeof crypto !== "undefined" && "randomUUID" in crypto) {
43	    return crypto.randomUUID();
44	  }
45	  return `onboarding-todo-${Date.now()}-${Math.random().toString(36).slice(2)}`;
46	}
47	
48	export interface SelectedTodoIndicatorProps {
49	  title: string;
50	  sourceEmail: { sender: string; subject: string } | null;
51	}
52	
53	/** Static "selected todo" indicator rendered above the run-now demo stream.
54	 *  Replaces the previous chat-bubble-shaped TodoRunNowCard so the auto-sent
55	 *  user message never reads as a real conversation turn. Exported for the
56	 *  onboarding demo sandbox. */
57	export function SelectedTodoIndicator({
58	  title,
59	  sourceEmail,
60	}: SelectedTodoIndicatorProps) {
61	  return (
62	    <div className="rounded-2xl bg-zinc-900 p-3">
63	      <Chip
64	        color="success"
65	        variant="flat"
66	        size="sm"
67	        startContent={<CheckmarkCircle02Icon className="size-3.5" />}
68	      >
69	        Selected todo
70	      </Chip>
71	      <div className="mt-2 text-sm text-white">{title}</div>
72	      {sourceEmail && (
73	        <div className="mt-3 flex items-start gap-2 rounded-xl bg-zinc-800 p-3">
74	          <Mail01Icon className="mt-0.5 size-3.5 shrink-0 text-zinc-500" />
75	          <div className="min-w-0 flex-1">
76	            <div className="truncate text-xs text-zinc-400">
77	              {sourceEmail.sender}
78	            </div>
79	            <div className="truncate text-xs text-zinc-500">
80	              {sourceEmail.subject}
81	            </div>
82	          </div>
83	        </div>
84	      )}
85	    </div>
86	  );
87	}
88	
89	/** Composer for the `revealTodos` stage. Renders a "Continue" CTA in the
90	 *  pinned footer once the run-now demo finishes — replaces the old inline
91	 *  button that used to sit beneath the todo result. */
92	export function RevealTodosComposer({
93	  dispatch,
94	  chat,
95	}: Pick<RevealTodosProps, "dispatch" | "chat">) {
96	  if (!chat.isTodoExecutionDone) return null;
97	  return (
98	    <m.div className="flex justify-center pb-2" {...MOTION_COMPOSER_CTA}>
99	      <OnboardingCTAButton onClick={() => dispatch({ type: "ackTodoDemo" })}>
100	        Continue
101	      </OnboardingCTAButton>
102	    </m.div>
103	  );
104	}
105	
106	export function RevealTodos({ state, dispatch, chat }: RevealTodosProps) {
107	  const todos = state.server?.onboarding_todos ?? [];
108	
109	  const handleExecute = useCallback(
110	    (todoId: string) => {
111	      const todo = todos.find((t) => t.id === todoId);
112	      if (!todo) return;
113	      const sourceEmail = todo.source_email ?? null;
114	      const emailHint = sourceEmail
115	        ? `\n\n[Context: derived from an email from "${sourceEmail.sender}" with subject "${sourceEmail.subject}". Reference this email and its actual contents.]`
116	        : "";
117	      const closingHint =
118	        "\n\n[This is an onboarding run-now demo. Execute the todo and report the result in 1-2 short sentences. Do NOT ask a follow-up question. Do NOT offer further help or automation. End on the result.]";
119	      const message = `Execute this todo for me: ${todo.title}${emailHint}${closingHint}`;
120	      dispatch({
121	        type: "executeTodo",
122	        message,
123	        convoId: generateConvoId(),
124	        todo: { id: todo.id, title: todo.title, sourceEmail },
125	      });
126	    },
127	    [todos, dispatch],
128	  );
129	
130	  if (todos.length === 0) return null;
131	
132	  if (state.todoExecutionStarted) {
133	    const selected = state.todoExecutionTodo;
134	    return (
135	      <m.div
136	        className="mt-10 ml-10.75 space-y-4 rounded-2xl bg-zinc-800/40 p-4 backdrop-blur-xl"
137	        initial={{ opacity: 0 }}
138	        animate={{ opacity: 1 }}
139	        transition={{ duration: 0.3 }}
140	      >
141	        {selected && (
142	          <SelectedTodoIndicator
143	            title={selected.title}
144	            sourceEmail={selected.sourceEmail}
145	          />
146	        )}
147	        <OnboardingChatStream chat={chat} hideRunNowUserMessage hideBotAvatar />
148	      </m.div>
149	    );
150	  }
151	
152	  return (
153	    <div className="mt-3 space-y-4">
154	      <RevealIntroBubble text={REVEAL_TODOS_INTRO}>
155	        <OnboardingTodoCards
156	          todos={todos.map((t) => ({
157	            id: t.id,
158	            title: t.title,
159	            description: t.description ?? undefined,
160	            source_email: t.source_email ?? undefined,
161	          }))}
162	          onExecuteTodo={handleExecute}
163	          isExecuting={false}
164	          executingTodoId={null}
165	          completedTodoIds={new Set()}
166	        />
167	      </RevealIntroBubble>
168	
169	      <m.div
170	        className="flex justify-center"
171	        initial={{ opacity: 0 }}
172	        animate={{ opacity: 1 }}
173	        transition={{ delay: 1.5, duration: 0.4 }}
174	      >
175	        <Button
176	          variant="light"
177	          size="sm"
178	          className="text-xs text-zinc-400 hover:text-zinc-200"
179	          onPress={() => dispatch({ type: "ackTodos" })}
180	        >
181	          I'll do it later
182	        </Button>
183	      </m.div>
184	    </div>
185	  );
186	}
187

