      console.error("Failed to replace optimistic message:", error);
    }
  }

  if (bot_message_id && refs.current.botMessage) {
    refs.current.botMessage.message_id = bot_message_id;
    await persistBotMessage(conversationId, bot_message_id);
  }
};

