/**
 * `chat` stage. Renders the welcome conversation stream followed by the holo
 * card reveal. The composer is always a "Continue to GAIA" CTA — the onboarding
 * first message intentionally closes its own loop, so there is no free-chat
 * input here. Active once the backend has produced `first_message_conversation_id`.
 */

"use client";

import * as m from "motion/react-m";
import type { Dispatch } from "react";
import { useEffect } from "react";
import ChatBubbleBot from "@/features/chat/components/bubbles/bot/ChatBubbleBot";
import ChatBubbleUser from "@/features/chat/components/bubbles/user/ChatBubbleUser";
import { LoadingIndicator } from "@/features/chat/components/interface/LoadingIndicator";
import {
  BOT_BUBBLE_DEFAULTS,
  USER_BUBBLE_DEFAULTS,
} from "../../constants/bubbleDefaults";
import {
  MOTION_COMPOSER_CTA,
  MOTION_FADE_UP_LARGE,
  MOTION_STREAM_MESSAGE,
} from "../../constants/motion";
import {
  type UseOnboardingChatReturn,
  useOnboardingChat,
} from "../../hooks/useOnboardingChat";
import type { Action, OnboardingState } from "../../state/types";
import { OnboardingCTAButton } from "../OnboardingCTAButton";
import { HoloCardReveal } from "../reveal/HoloCardReveal";

interface ChatProps {
  state: OnboardingState;
  dispatch: Dispatch<Action>;
  chat: UseOnboardingChatReturn;
}

export interface OnboardingChatStages {
  /** Live welcome conversation — seeded by the backend, lands the user in
   *  `/c/{first_message_conversation_id}` after onboarding. Never receives
   *  the run-now demo. */
  welcome: UseOnboardingChatReturn;
  /** Throwaway conversation that runs the in-place run-now todo demo. Kept
   *  separate from `welcome` so the executed turn doesn't appear in the
   *  post-onboarding chat. */
  todoDemo: UseOnboardingChatReturn;
}

/**
 * Page-level hook that wires up two independent chat streams: the welcome
 * conversation (for the final `chat` stage) and a throwaway conversation
 * for the run-now todo demo. Splitting them stops the run-now turn from
 * bleeding into the welcome conversation when the user clicks
 * "Continue to GAIA". Also clears `todoExecutionMessage` once the demo
 * conversation has consumed it so a remount can't re-queue.
 */
export function useChatStage(
  state: OnboardingState,
  dispatch: Dispatch<Action>,
): OnboardingChatStages {
  const welcomeConvoId = state.server?.first_message_conversation_id ?? null;
  const todoDemoConvoId = state.todoExecutionConvoId;
  const pendingTodoMessage = state.todoExecutionMessage;

  const welcome = useOnboardingChat(welcomeConvoId, null);
  const todoDemo = useOnboardingChat(todoDemoConvoId, pendingTodoMessage);

  useEffect(() => {
    if (!pendingTodoMessage || !todoDemoConvoId) return;
    dispatch({ type: "clearTodoExecutionMessage" });
  }, [pendingTodoMessage, todoDemoConvoId, dispatch]);

  return { welcome, todoDemo };
}

const RUN_NOW_PREFIX = "Execute this todo for me: ";

/** Shared stream renderer — used by both the in-place todo demo inside
 *  `revealTodos` and by the final `chat` stage. When `hideRunNowUserMessage`
 *  is true, the auto-sent "Execute this todo for me: ..." user turn is
 *  filtered out entirely (the demo container shows a static "selected todo"
 *  indicator instead). */
export function OnboardingChatStream({
  chat,
  hideRunNowUserMessage = false,
  hideBotAvatar = false,
}: {
  chat: UseOnboardingChatReturn;
  hideRunNowUserMessage?: boolean;
  hideBotAvatar?: boolean;
}) {
  const visibleMessages = hideRunNowUserMessage
    ? chat.streamMessages.filter(
        (msg) =>
          !(
            msg.role === "user" &&
            typeof msg.content === "string" &&
            msg.content.startsWith(RUN_NOW_PREFIX)
          ),
      )
    : chat.streamMessages;
  return (
    <>
      {visibleMessages.map((msg) => (
        <m.div key={msg.id} {...MOTION_STREAM_MESSAGE}>
          {msg.role === "user" ? (
            <ChatBubbleUser
              {...USER_BUBBLE_DEFAULTS}
              text={msg.content}
              message_id={msg.id}
              date={msg.createdAt.toISOString()}
              fileData={msg.fileData}
            />
          ) : (
            <ChatBubbleBot
              {...BOT_BUBBLE_DEFAULTS}
              text={msg.content}
              message_id={msg.id}
              loading={msg.status === "sending"}
              tool_data={msg.tool_data ?? undefined}
              todo_progress={msg.todo_progress ?? undefined}
              memory_data={msg.memory_data ?? undefined}
              image_data={msg.image_data ?? undefined}
              date={msg.createdAt.toISOString()}
              hideAvatar={hideBotAvatar}
            />
          )}
        </m.div>
      ))}

      {chat.isChatSending &&
        !visibleMessages.some(
          (msg) => msg.role === "assistant" && msg.content,
        ) && (
          <LoadingIndicator
            loadingText={
              hideRunNowUserMessage
                ? "Auto-executing todo…"
                : "GAIA is thinking…"
            }
            loadingTextKey={0}
          />
        )}
    </>
  );
}

export function Chat({ state }: Omit<ChatProps, "dispatch" | "chat">) {
  const showHolo = state.server?.has_personalization && state.server;
  if (!showHolo || !state.server) return null;

  const firstMessage = state.server.first_message;

  return (
    <m.div className="mt-4 space-y-4" {...MOTION_FADE_UP_LARGE}>
      {firstMessage && (
        <ChatBubbleBot
          {...BOT_BUBBLE_DEFAULTS}
          text={firstMessage}
          message_id="onboarding-first-message"
          loading={false}
          date={new Date().toISOString()}
        />
      )}
      <div className="my-4">
        <HoloCardReveal personalizationData={state.server} />
      </div>
    </m.div>
  );
}

/** Composer for the `chat` stage. Always renders the "Continue to GAIA" CTA —
 *  the onboarding chat stage ends with a closed-loop message (no question), so
 *  the user's only forward move is into the full chat experience. The CTA
 *  lands the user inside the seeded welcome conversation when available so
 *  the post-onboarding welcome UI shows up immediately. */
export function ChatComposer({ state }: Omit<ChatProps, "dispatch" | "chat">) {
  const welcomeConvoId = state.server?.first_message_conversation_id;
  const href = welcomeConvoId ? `/c/${welcomeConvoId}` : "/c";
  return (
    <m.div className="flex justify-center pb-2" {...MOTION_COMPOSER_CTA}>
      <OnboardingCTAButton href={href}>Continue to GAIA</OnboardingCTAButton>
    </m.div>
  );
}

/**
 * `revealTodos` stage. Active once `onboarding_todos` is non-empty and the
 * user hasn't acked yet.
 *
 * Two sub-states:
 * - **Grid mode** (default): show the suggested todos. User can click "Run"
 *   on one (→ `executeTodo`, flips into stream mode) or "I'll do it later"
 *   (→ `ackTodos`, advances to workflows).
 * - **Stream mode** (`state.todoExecutionStarted`): the todo grid is replaced
 *   in-place by the live chat stream so the agent's processing is visible
 *   without leaving the onboarding shell. Once the agent finishes
 *   (`chat.isTodoExecutionDone`) a Continue button dispatches `ackTodoDemo`
 *   to advance to the workflows stage.
 */

"use client";

import { Button } from "@heroui/button";
import { Chip } from "@heroui/chip";
import { CheckmarkCircle02Icon, Mail01Icon } from "@icons";
import * as m from "motion/react-m";
import type { Dispatch } from "react";
import { useCallback } from "react";
import { REVEAL_TODOS_INTRO } from "../../constants/messages";
import { MOTION_COMPOSER_CTA } from "../../constants/motion";
import type { UseOnboardingChatReturn } from "../../hooks/useOnboardingChat";
import type { Action, OnboardingState } from "../../state/types";
import { OnboardingCTAButton } from "../OnboardingCTAButton";
import { OnboardingTodoCards } from "../OnboardingTodoCards";
import { RevealIntroBubble } from "../RevealIntroBubble";
import { OnboardingChatStream } from "./Chat";

interface RevealTodosProps {
  state: OnboardingState;
  dispatch: Dispatch<Action>;
  /** Run-now demo chat — separate throwaway conversation, NOT the welcome
   *  conversation. See `useChatStage`. */
  chat: UseOnboardingChatReturn;
}

function generateConvoId(): string {
  if (typeof crypto !== "undefined" && "randomUUID" in crypto) {
    return crypto.randomUUID();
  }
  return `onboarding-todo-${Date.now()}-${Math.random().toString(36).slice(2)}`;
}

export interface SelectedTodoIndicatorProps {
  title: string;
  sourceEmail: { sender: string; subject: string } | null;
}

/** Static "selected todo" indicator rendered above the run-now demo stream.
 *  Replaces the previous chat-bubble-shaped TodoRunNowCard so the auto-sent
 *  user message never reads as a real conversation turn. Exported for the
 *  onboarding demo sandbox. */
export function SelectedTodoIndicator({
  title,
  sourceEmail,
}: SelectedTodoIndicatorProps) {
  return (
    <div className="rounded-2xl bg-zinc-900 p-3">
      <Chip
        color="success"
        variant="flat"
        size="sm"
        startContent={<CheckmarkCircle02Icon className="size-3.5" />}
      >
        Selected todo
      </Chip>
      <div className="mt-2 text-sm text-white">{title}</div>
      {sourceEmail && (
        <div className="mt-3 flex items-start gap-2 rounded-xl bg-zinc-800 p-3">
          <Mail01Icon className="mt-0.5 size-3.5 shrink-0 text-zinc-500" />
          <div className="min-w-0 flex-1">
            <div className="truncate text-xs text-zinc-400">
              {sourceEmail.sender}
            </div>
            <div className="truncate text-xs text-zinc-500">
              {sourceEmail.subject}
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

/** Composer for the `revealTodos` stage. Renders a "Continue" CTA in the
 *  pinned footer once the run-now demo finishes — replaces the old inline
 *  button that used to sit beneath the todo result. */
export function RevealTodosComposer({
  dispatch,
  chat,
}: Pick<RevealTodosProps, "dispatch" | "chat">) {
  if (!chat.isTodoExecutionDone) return null;
  return (
    <m.div className="flex justify-center pb-2" {...MOTION_COMPOSER_CTA}>
      <OnboardingCTAButton onClick={() => dispatch({ type: "ackTodoDemo" })}>
        Continue
      </OnboardingCTAButton>
    </m.div>
  );
}

export function RevealTodos({ state, dispatch, chat }: RevealTodosProps) {
  const todos = state.server?.onboarding_todos ?? [];

  const handleExecute = useCallback(
    (todoId: string) => {
      const todo = todos.find((t) => t.id === todoId);
      if (!todo) return;
      const sourceEmail = todo.source_email ?? null;
      const emailHint = sourceEmail
        ? `\n\n[Context: derived from an email from "${sourceEmail.sender}" with subject "${sourceEmail.subject}". Reference this email and its actual contents.]`
        : "";
      const closingHint =
        "\n\n[This is an onboarding run-now demo. Execute the todo and report the result in 1-2 short sentences. Do NOT ask a follow-up question. Do NOT offer further help or automation. End on the result.]";
      const message = `Execute this todo for me: ${todo.title}${emailHint}${closingHint}`;
      dispatch({
        type: "executeTodo",
        message,
        convoId: generateConvoId(),
        todo: { id: todo.id, title: todo.title, sourceEmail },
      });
    },
    [todos, dispatch],
  );

  if (todos.length === 0) return null;

  if (state.todoExecutionStarted) {
    const selected = state.todoExecutionTodo;
    return (
      <m.div
        className="mt-10 ml-10.75 space-y-4 rounded-2xl bg-zinc-800/40 p-4 backdrop-blur-xl"
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        transition={{ duration: 0.3 }}
      >
        {selected && (
          <SelectedTodoIndicator
            title={selected.title}
            sourceEmail={selected.sourceEmail}
          />
        )}
        <OnboardingChatStream chat={chat} hideRunNowUserMessage hideBotAvatar />
      </m.div>
    );
  }

  return (
    <div className="mt-3 space-y-4">
      <RevealIntroBubble text={REVEAL_TODOS_INTRO}>
        <OnboardingTodoCards
          todos={todos.map((t) => ({
            id: t.id,
            title: t.title,
            description: t.description ?? undefined,
            source_email: t.source_email ?? undefined,
          }))}
          onExecuteTodo={handleExecute}
          isExecuting={false}
          executingTodoId={null}
          completedTodoIds={new Set()}
        />
      </RevealIntroBubble>

      <m.div
        className="flex justify-center"
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        transition={{ delay: 1.5, duration: 0.4 }}
      >
        <Button
          variant="light"
          size="sm"
          className="text-xs text-zinc-400 hover:text-zinc-200"
          onPress={() => dispatch({ type: "ackTodos" })}
        >
          I'll do it later
        </Button>
      </m.div>
    </div>
  );
}

